/**
 * Email notification handler for order lifecycle events.
 *
 * Subscribes to EventBus events and formats email notifications
 * for order status changes and order creation. Uses the same
 * EventBus pattern as NotificationService for consistency.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const statusLabels: Record<OrderStatus, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

function getStatusEmoji(status: OrderStatus): string {
  const emojis: Record<OrderStatus, string> = {
    pending: '&#9203;',
    confirmed: '&#9989;',
    shipped: '&#128666;',
    delivered: '&#127881;',
    cancelled: '&#10060;',
  };
  return emojis[status];
}

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td><td>$${(item.quantity * item.unitPrice).toFixed(2)}</td></tr>`,
      )
      .join('');

    const itemText = event.order.items
      .map(
        (item) =>
          `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)} = $${(item.quantity * item.unitPrice).toFixed(2)}`,
      )
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Hi ${event.user.name},</p>
<p>Your order <strong>${event.order.id}</strong> has been placed successfully.</p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th><th>Subtotal</th></tr>
${itemRows}
</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`;

    const textBody = `Order Confirmation

Hi ${event.user.name},

Your order ${event.order.id} has been placed successfully.

Items:
${itemText}

Total: $${event.order.total.toFixed(2)}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const newStatus = event.newStatus as OrderStatus;
    const previousStatus = event.previousStatus as OrderStatus;

    this.logger.info(
      `Sending status change email for order ${event.order.id}: ${previousStatus} -> ${newStatus}`,
    );

    const statusEmoji = getStatusEmoji(newStatus);
    const statusLabel = statusLabels[newStatus];
    const previousLabel = statusLabels[previousStatus];

    const htmlBody = `<h1>Order Status Update</h1>
<p>Your order <strong>${event.order.id}</strong> has been updated.</p>
<p>Status: ${previousLabel} &rarr; ${statusEmoji} <strong>${statusLabel}</strong></p>
${this.getStatusMessage(newStatus)}`;

    const textBody = `Order Status Update

Your order ${event.order.id} has been updated.

Status: ${previousLabel} -> ${statusLabel}

${this.getStatusTextMessage(newStatus)}`;

    this.sendEmail({
      to: event.order.userId,
      subject: `Order ${event.order.id} - ${statusLabel}`,
      htmlBody,
      textBody,
    });
  }

  private getStatusMessage(status: OrderStatus): string {
    switch (status) {
      case 'confirmed':
        return '<p>Your order has been confirmed and is being prepared.</p>';
      case 'shipped':
        return '<p>Your order has been shipped and is on its way!</p>';
      case 'delivered':
        return '<p>Your order has been delivered. Enjoy!</p>';
      case 'cancelled':
        return '<p>Your order has been cancelled.</p>';
      default:
        return '';
    }
  }

  private getStatusTextMessage(status: OrderStatus): string {
    switch (status) {
      case 'confirmed':
        return 'Your order has been confirmed and is being prepared.';
      case 'shipped':
        return 'Your order has been shipped and is on its way!';
      case 'delivered':
        return 'Your order has been delivered. Enjoy!';
      case 'cancelled':
        return 'Your order has been cancelled.';
      default:
        return '';
    }
  }

  private sendEmail(params: Omit<EmailMessage, 'sentAt'>): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  getSentEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationHandler } from '../../src/notifications/email-notification-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
  });

  describe('order:created emails', () => {
    it('should send a confirmation email when an order is created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include item details in HTML body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('Gadget');
      expect(email.htmlBody).toContain('$45.00');
      expect(email.htmlBody).toContain('<table>');
    });

    it('should include item details in text body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 5 },
          ],
          total: 15,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x3');
      expect(email.textBody).toContain('$15.00');
      expect(email.textBody).toContain('Hi Bob');
    });
  });

  describe('order:status-changed emails', () => {
    const makeStatusEvent = (
      previousStatus: string,
      newStatus: string,
    ): OrderStatusChangedEvent => ({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: newStatus as 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus,
      newStatus,
      timestamp: new Date(),
    });

    it('should send an email when order status changes to confirmed', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('Confirmed');
      expect(emails[0]?.htmlBody).toContain('confirmed and is being prepared');
    });

    it('should send an email when order status changes to shipped', async () => {
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Shipped');
      expect(emails[0]?.htmlBody).toContain('shipped and is on its way');
    });

    it('should send an email when order status changes to delivered', async () => {
      await eventBus.emit(makeStatusEvent('shipped', 'delivered'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Delivered');
      expect(emails[0]?.htmlBody).toContain('delivered');
      expect(emails[0]?.textBody).toContain('Enjoy');
    });

    it('should send an email when order is cancelled', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'cancelled'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Cancelled');
      expect(emails[0]?.htmlBody).toContain('cancelled');
    });

    it('should include both previous and new status in email body', async () => {
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Confirmed');
      expect(email.htmlBody).toContain('Shipped');
      expect(email.textBody).toContain('Confirmed');
      expect(email.textBody).toContain('Shipped');
    });
  });

  describe('email management', () => {
    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(handler.getSentEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getSentEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear sent emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearSentEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });

    it('should track multiple emails across events', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(2);
      expect(handler.getSentEmails()[0]?.subject).toContain('Confirmed');
      expect(handler.getSentEmails()[1]?.subject).toContain('Shipped');
    });
  });

  describe('coexistence with NotificationService', () => {
    it('should work alongside NotificationService on the same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();
      const notificationService = new NotificationService(eventBus);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      // Both handlers should have received the event
      expect(handler.getSentEmailCount()).toBe(1);
      expect(notificationService.getNotificationCount()).toBe(1);
    });
  });
});

